import React, {useState, useEffect} from 'react';

import VINS from './img/1.png'
import VINS_SUCCESS from './img/success.png'
import VINS_ERROR from './img/error.png'

const Main = () => {
    const [isStarted, setIsStarted] = useState(false)
    const [isToolTipOpen, setIsToolTipOpen] = useState(false)

    const [code, setCode] = useState('')

    const [isDone, setIsDone] = useState(false)

    const [isError, setIsError] = useState(false)

    // useEffect(() => {
    //     [VINS, VINS_SUCCESS, VINS_ERROR].forEach(img => {
    //         const IMAGE = new Image()
    //         IMAGE.src = img
    //     })
    // }, [])

    const startApp = () => {
        setIsStarted(true)
    }

    const openToolTip = () => {
        console.log('openToolTip')
        setIsToolTipOpen(!isToolTipOpen)
    }

    const handleCodeChange = e => {

        isError && setIsError(false)
        setCode(e.target.value)
    }

    const submit = e => {
        if (code !== '96813') {
            setIsError(true)
            return
        }
        setIsDone(true)
    }

    return (
        <div className='main'>

            {!isStarted && (
                <>
                <button className='start-btn' onClick={startApp}><b>Узнать где подарок</b></button>
                    <img className='vins' src={VINS_ERROR} alt="" style={{position: 'absolute', height: 1, width: 1, opacity: 0}}/>
                    <img className='vins' src={VINS_SUCCESS} alt="" style={{position: 'absolute', height: 1, width: 1, opacity: 0}}/>
                    <img className='vins' src={VINS} alt="" style={{position: 'absolute', height: 1, width: 1, opacity: 0}}/>
                </>
            )}

            {!isDone && isStarted && (
                <div style={{marginTop: 25}}>

                    {
                        isError
                            ? <img className='vins' src={VINS_ERROR} alt=""/>
                            : <img className='vins' src={VINS} alt=""/>
                    }

                    {
                        isError
                            ? <p style={{maxWidth: 250}}>Не правильный код! =(<br/><br/></p>
                            : <p style={{maxWidth: 250}}>Для того чтобы узнать где подарок, нужно ввести код =)</p>
                    }



                    <label htmlFor="" style={{display: "flex", alignItems: 'center', justifyContent: 'center'}}>
                        <input placeholder='Код...' value={code} onChange={handleCodeChange}/>

                        <button className='submit' onClick={submit}>
                            <i className="fas fa-arrow-right" style={{fontSize: 20}}/>
                        </button>
                    </label>


                    <a onClick={openToolTip}>

                        <p style={{color: '#3F51B5'}}>Как узнать код?</p>
                    </a>
                </div>
            )}


            {!isDone && (

                <div className={'tooltipWrap ' + (isToolTipOpen ? 'tooltipWrap-open' : '')}>
                    <div>
                        <a onClick={openToolTip} className='close-tooltip'>Закрыть</a>

                        <p style={{color: '#4481dd', marginTop: 50, textAlign: 'center', marginLeft: 10,marginRight: 10, maxWidth: 999,}}>
                            Код придётся найти по частям =)
                            <br/>
                            Все подсказки находится в моей комнате
                        </p>

                        <h4 style={{color: '#4481dd', textAlign: 'left', marginLeft: 10, marginBottom: 5}}>Первая подсказка:</h4>
                        <p style={{color: '#4481dd',  textAlign: 'center', marginLeft: 10,marginRight: 10, maxWidth: 999, marginTop: 5}}><i>Посмотри в "спортивной таре"</i></p>
                        <p></p>
                    </div>
                </div>
            )}

            {isDone && (
                <div style={{marginTop: 25}}>
                <img className='vins' src={VINS_SUCCESS} alt=""/>
                <h4 style={{color: '#fff'}}>Правильно!!!</h4>
                    <p>Питерь загляни в коробку от другого твоего подарка :3
                        <br/>
                        <br/>
                        <span style={{fontSize: 10, opacity: 0.7}}>Спроси у меня подсказку, если что =)</span>
                    </p>
            </div>
                )
            }


        </div>
    );
}

export default Main;
